import json
import re
from pathlib import Path

SRC = Path("/c/Users/yuram/.claude/projects/--wsl-localhost-Ubuntu-home-yuriy-TaskTracker/be252251-bf5f-4f67-a345-02e4691ad56d.jsonl")

def strip_meta(text: str) -> str:
    """Remove IDE-injected and system-reminder XML-like blocks from user text."""
    text = re.sub(r"<ide_opened_file>.*?</ide_opened_file>", "", text, flags=re.S)
    text = re.sub(r"<ide_selection>.*?</ide_selection>", "", text, flags=re.S)
    text = re.sub(r"<system-reminder>.*?</system-reminder>", "", text, flags=re.S)
    text = re.sub(r"<command-name>.*?</command-name>", "", text, flags=re.S)
    return text.strip()

def extract_user_text(content):
    if isinstance(content, str):
        return strip_meta(content)
    if not isinstance(content, list):
        return ""
    parts = []
    for block in content:
        if not isinstance(block, dict):
            continue
        if block.get("type") == "text":
            parts.append(block.get("text", ""))
        # skip tool_result blocks - these are tool outputs not user input
    text = "\n\n".join(p for p in parts if p)
    return strip_meta(text)

def extract_assistant_text(content):
    if isinstance(content, str):
        return content.strip()
    if not isinstance(content, list):
        return ""
    parts = []
    for block in content:
        if not isinstance(block, dict):
            continue
        if block.get("type") == "text":
            parts.append(block.get("text", ""))
        # skip tool_use, thinking
    return "\n\n".join(p for p in parts if p).strip()

turns = []
for raw in SRC.read_text(encoding="utf-8").splitlines():
    if not raw.strip():
        continue
    try:
        obj = json.loads(raw)
    except json.JSONDecodeError:
        continue
    t = obj.get("type")
    if t == "user":
        msg = obj.get("message", {})
        text = extract_user_text(msg.get("content"))
        if text:
            turns.append(("user", obj.get("timestamp", ""), text))
    elif t == "assistant":
        msg = obj.get("message", {})
        text = extract_assistant_text(msg.get("content"))
        if text:
            turns.append(("assistant", obj.get("timestamp", ""), text))

print(f"Extracted turns: {len(turns)}")
print(f"Total text size: {sum(len(t[2]) for t in turns)} chars")
PYEOF
